Citation Metrics
Data sourced live from OpenAlex.

ekc = await fetch("https://api.openalex.org/works/https://doi.org/10.21511/ee.12(1).2021.06")
  .then(r =&gt; r.json())

anacarde = await fetch("https://api.openalex.org/works/https://doi.org/10.19044/esj.2018.v14n30p292")
  .then(r =&gt; r.json())

// Build combined dataset
data = {
  const ekc_rows = (ekc.counts_by_year || []).map(d =&gt; ({
    year: d.year,
    citations: d.cited_by_count,
    paper: "EKC West Africa (2021)"
  }))
  const ana_rows = (anacarde.counts_by_year || []).map(d =&gt; ({
    year: d.year,
    citations: d.cited_by_count,
    paper: "Cashew Farmers CI (2018)"
  }))
  return [...ekc_rows, ...ana_rows].sort((a,b) =&gt; a.year - b.year)
}

// Summary cards
html`
&lt;div style="display:flex; gap:2rem; margin-bottom:1.5rem; flex-wrap:wrap;"&gt;
  &lt;div style="background:#002366; color:white; border-radius:8px; padding:1rem 2rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${ekc.cited_by_count}&lt;/div&gt;
    &lt;div style="font-size:0.85rem; opacity:0.85;"&gt;citations — EKC West Africa&lt;/div&gt;
  &lt;/div&gt;
  &lt;div style="background:#002366; color:white; border-radius:8px; padding:1rem 2rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${anacarde.cited_by_count}&lt;/div&gt;
    &lt;div style="font-size:0.85rem; opacity:0.85;"&gt;citations — Cashew Farmers CI&lt;/div&gt;
  &lt;/div&gt;
  &lt;div style="background:#1a4a8a; color:white; border-radius:8px; padding:1rem 2rem; text-align:center;"&gt;
    &lt;div style="font-size:2rem; font-weight:700;"&gt;${ekc.cited_by_count + anacarde.cited_by_count}&lt;/div&gt;
    &lt;div style="font-size:0.85rem; opacity:0.85;"&gt;total citations&lt;/div&gt;
  &lt;/div&gt;
&lt;/div&gt;`




























Plot.plot({
  title: "Citations per year",
  width: 650,
  height: 300,
  marginLeft: 50,
  x: { label: "Year", tickFormat: d =&gt; String(d) },
  y: { label: "Citations", grid: true },
  color: { legend: true, range: ["#002366", "#e8a020"] },
  marks: [
    Plot.barY(data, {
      x: "year",
      y: "citations",
      fill: "paper",
      fx: "paper",
      tip: true
    }),
    Plot.ruleY([0])
  ]
})
